code.Java:
import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] a = new int[n];
        for (int i = 0; i < n; i++) {
            a[i] = scanner.nextInt();
        }
        Arrays.sort(a);
        int count = 0;
        for (int i = 0; i < n - 1; i++) {
            if (a[i] == a[i + 1]) {
                count++;
                i++;
            }
        }
        System.out.println(count);
    }
}

code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let a = [];
readline.on('line', line => {
    if (i == 0) {
        n = parseInt(line);
    } else {
        a = line.split(' ').map(num => parseInt(num));
        a.sort((a, b) => a - b);
        let count = 0;
        for (let j = 0; j < n - 1; j++) {
            if (a[j] == a[j + 1]) {
                count++;
                j++;
            }
        }
        console.log(count);
    }
    i++;
});

